codeExample:
// Interface merging (declaration merging)
interface User { name: string; }
interface User { age: number; }  // merged — User now has both

// Type cannot do this:
type Config = { timeout: number } & { retries: number }; // intersection instead

function identity<T>(value: T): T {
  return value;
}

const s = identity('hello'); // s: string
const n = identity(42);      // n: number

// With constraints:
function getLength<T extends { length: number }>(arg: T): number {
  return arg.length;
}

type Shape =
  | { kind: 'circle'; radius: number }
  | { kind: 'square'; side: number };

function area(s: Shape): number {
  switch (s.kind) {
    case 'circle': return Math.PI * s.radius ** 2;
    case 'square': return s.side ** 2;
  }
}

type Nullable<T> = { [K in keyof T]: T[K] | null };

type User = { name: string; age: number };
type NullableUser = Nullable<User>;
// { name: string | null; age: number | null }

type UnpackPromise<T> = T extends Promise<infer R> ? R : T;

type A = UnpackPromise<Promise<string>>; // string
type B = UnpackPromise<number>;          // number (not a Promise, returns T)

// Built-in uses the same pattern:
type ReturnType<F> = F extends (...args: any) => infer R ? R : never;

// Extract the element type of an array:
type ElementType<T> = T extends (infer E)[] ? E : never;

type A = ElementType<string[]>;  // string
type B = ElementType<number[][]>; // number[]

// Extract first argument:
type FirstArg<F> = F extends (a: infer A, ...rest: any) => any ? A : never;

const config = { host: 'localhost', port: 3000 };
type ConfigKey = keyof typeof config; // 'host' | 'port'

function get(key: ConfigKey) {
  return config[key]; // fully type-safe
}

// augmenting Express
declare module 'express-serve-static-core' {
  interface Request {
    user?: { id: string; role: string };
  }
}
